            || ecp_sm2p256_bignum_field_elem(p.p.X, point[i]->X) <= 0
            || ecp_sm2p256_bignum_field_elem(p.p.Y, point[i]->Y) <= 0
            || ecp_sm2p256_bignum_field_elem(p.p.Z, point[i]->Z) <= 0) {
            ECerr(ERR_LIB_EC, EC_R_COORDINATES_OUT_OF_RANGE);
            goto err;
        }

